# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib.request
import urllib.error
import base64


def lambda_handler(event, context):
    """
    Lambda@Edge Viewer Request function that enriches requests by fetching
    additional data from URLs specified in request headers.
    
    Reads URLs from X-Enrich-URL headers (comma-separated if multiple),
    fetches data from each URL, and adds the enrichment data as new headers
    before forwarding to origin.
    """
    request = event['Records'][0]['cf']['request']
    headers = request.get('headers', {})
    
    # Check for the X-Enrich-URL header
    enrich_header_key = 'x-enrich-url'
    
    if enrich_header_key not in headers:
        # No enrichment requested, pass through
        return request
    
    # Extract all enrichment URLs from the header(s)
    enrich_urls = []
    for header_entry in headers[enrich_header_key]:
        # Support comma-separated URLs in a single header value
        urls = [url.strip() for url in header_entry['value'].split(',')]
        enrich_urls.extend(urls)
    
    # Fetch data from each enrichment URL
    enrichment_results = []
    enrichment_errors = []
    
    for idx, url in enumerate(enrich_urls):
        if not url:
            continue
            
        # Validate URL scheme - only allow http and https
        if not url.startswith(('http://', 'https://')):
            enrichment_errors.append({
                'url': url,
                'error': 'Invalid URL scheme. Only http and https are allowed.'
            })
            continue
        
        try:
            result = _fetch_url(url)
            enrichment_results.append({
                'url': url,
                'status': result['status'],
                'data': result['body']
            })
        except Exception as e:
            enrichment_errors.append({
                'url': url,
                'error': str(e)
            })
    
    # Add enrichment data as headers to the request
    # Base64 encode the JSON to safely pass in headers
    if enrichment_results:
        enrichment_payload = json.dumps(enrichment_results)
        encoded_payload = base64.b64encode(enrichment_payload.encode('utf-8')).decode('utf-8')
        
        # Lambda@Edge has a header size limit (~8KB for viewer request)
        # Split into chunks if necessary
        max_header_size = 7680  # Leave some room under the 8KB limit
        
        if len(encoded_payload) <= max_header_size:
            request['headers']['x-enrichment-data'] = [{
                'key': 'X-Enrichment-Data',
                'value': encoded_payload
            }]
        else:
            # Chunk the payload across multiple indexed headers
            chunks = _chunk_string(encoded_payload, max_header_size)
            for chunk_idx, chunk in enumerate(chunks):
                header_name = f'x-enrichment-data-{chunk_idx}'
                request['headers'][header_name] = [{
                    'key': f'X-Enrichment-Data-{chunk_idx}',
                    'value': chunk
                }]
            request['headers']['x-enrichment-chunks'] = [{
                'key': 'X-Enrichment-Chunks',
                'value': str(len(chunks))
            }]
    
    # Add enrichment count header
    request['headers']['x-enrichment-count'] = [{
        'key': 'X-Enrichment-Count',
        'value': str(len(enrichment_results))
    }]
    
    # Add error information if any
    if enrichment_errors:
        error_payload = json.dumps(enrichment_errors)
        encoded_errors = base64.b64encode(error_payload.encode('utf-8')).decode('utf-8')
        request['headers']['x-enrichment-errors'] = [{
            'key': 'X-Enrichment-Errors',
            'value': encoded_errors
        }]
    
    # Add enrichment status header
    if enrichment_errors and not enrichment_results:
        status = 'failed'
    elif enrichment_errors and enrichment_results:
        status = 'partial'
    elif enrichment_results:
        status = 'success'
    else:
        status = 'no-urls'
    
    request['headers']['x-enrichment-status'] = [{
        'key': 'X-Enrichment-Status',
        'value': status
    }]
    
    # Remove the original enrichment URL header to avoid leaking internal URLs to origin
    # (optional - comment out if origin needs to see the original URLs)
    if enrich_header_key in request['headers']:
        del request['headers'][enrich_header_key]
    
    return request


def _fetch_url(url, timeout=2):
    """
    Fetch data from a URL using urllib (available in Lambda@Edge).
    
    Lambda@Edge does not support layers or custom packages,
    so we use urllib which is available in the standard library.
    
    Args:
        url: The URL to fetch
        timeout: Request timeout in seconds (keep low for edge performance)
    
    Returns:
        dict with 'status' and 'body' keys
    """
    req = urllib.request.Request(
        url,
        headers={
            'User-Agent': 'LambdaEdge-Enrichment/1.0',
            'Accept': 'application/json, text/plain, */*'
        },
        method='GET'
    )
    
    try:
        with urllib.request.urlopen(req, timeout=timeout) as response:
            body = response.read().decode('utf-8', errors='replace')
            
            # Truncate response body to prevent header size overflow
            max_body_size = 4096
            if len(body) > max_body_size:
                body = body[:max_body_size]
            
            # Try to parse as JSON for cleaner data
            try:
                body = json.loads(body)
            except (json.JSONDecodeError, ValueError):
                pass  # Keep as string
            
            return {
                'status': response.status,
                'body': body
            }
    except urllib.error.HTTPError as e:
        return {
            'status': e.code,
            'body': f'HTTP Error: {e.reason}'
        }
    except urllib.error.URLError as e:
        raise Exception(f'URL Error fetching {url}: {str(e.reason)}')
    except Exception as e:
        raise Exception(f'Error fetching {url}: {str(e)}')


def _chunk_string(s, chunk_size):
    """Split a string into chunks of specified size."""
    return [s[i:i + chunk_size] for i in range(0, len(s), chunk_size)]